# tests/test_architecture.py — using pytest-archon or custom AST inspection
import ast, pathlib, pytest

AGENT_ROOT = pathlib.Path("src/agents")
PROVIDER_PACKAGE = "src.providers"

def imports_of(filepath: pathlib.Path) -> list[str]:
    tree = ast.parse(filepath.read_text())
    return [
        node.names[0].name if isinstance(node, ast.Import)
        else node.module
        for node in ast.walk(tree)
        if isinstance(node, (ast.Import, ast.ImportFrom))
        and getattr(node, "module", None)
    ]

def test_orchestrator_does_not_import_provider_directly():
    """Orchestrator layer must access providers only through the abstraction layer."""
    violations = []
    for path in (AGENT_ROOT / "orchestrator").rglob("*.py"):
        for imp in imports_of(path):
            if imp and imp.startswith(PROVIDER_PACKAGE):
                violations.append(f"{path}: imports {imp}")
    assert not violations, "\n".join(violations)

def test_retrieval_does_not_import_orchestrator():
    """Retrieval modules must not depend on orchestration logic (acyclic dependency)."""
    violations = []
    for path in (AGENT_ROOT / "retrieval").rglob("*.py"):
        for imp in imports_of(path):
            if imp and "orchestrator" in imp:
                violations.append(f"{path}: imports {imp}")
    assert not violations, "\n".join(violations)

# Contract test: output schema validation
import jsonschema, pytest
from src.agents.retrieval import RetrievalAgent

RETRIEVAL_OUTPUT_SCHEMA = {
    "type": "object",
    "required": ["chunks", "metadata"],
    "properties": {
        "chunks": {"type": "array", "items": {"type": "string"}},
        "metadata": {
            "type": "object",
            "required": ["source", "retrieved_at"],
        },
    },
    "additionalProperties": False,
}

def test_retrieval_output_schema():
    agent = RetrievalAgent()
    result = agent.retrieve("test query about permissions")
    jsonschema.validate(result, RETRIEVAL_OUTPUT_SCHEMA)  # raises if schema violated
